export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    try {
      // Route requests to appropriate internal workers via service bindings
      if (path.startsWith('/api/users')) {
        return await routeToUserService(request, env, path);
      }

      if (path.startsWith('/api/products')) {
        return await routeToProductService(request, env, path);
      }

      if (path.startsWith('/api/orders')) {
        return await routeToOrderService(request, env, path);
      }

      if (path === '/api/health') {
        return await healthCheck(env);
      }

      return new Response(JSON.stringify({
        error: 'Not Found',
        message: `No route matched for ${path}`,
        availableRoutes: ['/api/users', '/api/products', '/api/orders', '/api/health']
      }), {
        status: 404,
        headers: { 'Content-Type': 'application/json' }
      });

    } catch (err) {
      console.error(`Gateway error: ${err.message}`);
      return new Response(JSON.stringify({
        error: 'Internal Gateway Error',
        message: err.message,
        timestamp: new Date().toISOString()
      }), {
        status: 502,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

async function routeToUserService(request, env, path) {
  // Strip the /api/users prefix and forward to user service
  const internalUrl = new URL(request.url);
  internalUrl.pathname = path.replace('/api/users', '/users');

  const internalRequest = new Request(internalUrl.toString(), {
    method: request.method,
    headers: addGatewayHeaders(request.headers),
    body: request.method !== 'GET' && request.method !== 'HEAD' ? request.body : null,
  });

  const response = await env.USER_SERVICE.fetch(internalRequest);
  return addCorsHeaders(response);
}

async function routeToProductService(request, env, path) {
  const internalUrl = new URL(request.url);
  internalUrl.pathname = path.replace('/api/products', '/products');

  const internalRequest = new Request(internalUrl.toString(), {
    method: request.method,
    headers: addGatewayHeaders(request.headers),
    body: request.method !== 'GET' && request.method !== 'HEAD' ? request.body : null,
  });

  const response = await env.PRODUCT_SERVICE.fetch(internalRequest);
  return addCorsHeaders(response);
}

async function routeToOrderService(request, env, path) {
  const internalUrl = new URL(request.url);
  internalUrl.pathname = path.replace('/api/orders', '/orders');

  const internalRequest = new Request(internalUrl.toString(), {
    method: request.method,
    headers: addGatewayHeaders(request.headers),
    body: request.method !== 'GET' && request.method !== 'HEAD' ? request.body : null,
  });

  const response = await env.ORDER_SERVICE.fetch(internalRequest);
  return addCorsHeaders(response);
}

async function healthCheck(env) {
  const services = {
    gateway: 'healthy',
    userService: 'unknown',
    productService: 'unknown',
    orderService: 'unknown'
  };

  const checks = await Promise.allSettled([
    env.USER_SERVICE.fetch(new Request('https://internal/health')),
    env.PRODUCT_SERVICE.fetch(new Request('https://internal/health')),
    env.ORDER_SERVICE.fetch(new Request('https://internal/health')),
  ]);

  const serviceNames = ['userService', 'productService', 'orderService'];
  for (let i = 0; i < checks.length; i++) {
    if (checks[i].status === 'fulfilled' && checks[i].value.ok) {
      services[serviceNames[i]] = 'healthy';
    } else {
      services[serviceNames[i]] = 'unhealthy';
    }
  }

  const allHealthy = Object.values(services).every(s => s === 'healthy');

  return new Response(JSON.stringify({
    status: allHealthy ? 'healthy' : 'degraded',
    services,
    timestamp: new Date().toISOString()
  }), {
    status: allHealthy ? 200 : 503,
    headers: { 'Content-Type': 'application/json' }
  });
}

function addGatewayHeaders(originalHeaders) {
  const headers = new Headers(originalHeaders);
  headers.set('X-Gateway-Request-Id', crypto.randomUUID());
  headers.set('X-Gateway-Timestamp', new Date().toISOString());
  headers.set('X-Forwarded-By', 'edge-gateway');
  return headers;
}

function addCorsHeaders(response) {
  const newResponse = new Response(response.body, response);
  newResponse.headers.set('Access-Control-Allow-Origin', '*');
  newResponse.headers.set('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, OPTIONS');
  newResponse.headers.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  return newResponse;
}


