// Base class for internal service workers providing common functionality
class InternalServiceBase {
  constructor(serviceName) {
    this.serviceName = serviceName;
  }

  createJsonResponse(data, status = 200) {
    return new Response(JSON.stringify(data), {
      status,
      headers: {
        'Content-Type': 'application/json',
        'X-Service-Name': this.serviceName,
        'X-Service-Timestamp': new Date().toISOString()
      }
    });
  }

  createErrorResponse(message, status = 500) {
    return this.createJsonResponse({
      error: message,
      service: this.serviceName,
      timestamp: new Date().toISOString()
    }, status);
  }

  logRequest(request) {
    const gatewayId = request.headers.get('X-Gateway-Request-Id') || 'direct';
    console.log(`[${this.serviceName}] ${request.method} ${new URL(request.url).pathname} | gateway-id: ${gatewayId}`);
  }
}

class UserServiceRouter {
  constructor(env) {
    this.env = env;
    this.base = new InternalServiceBase('user-service');
  }

  async handleRequest(request) {
    this.base.logRequest(request);

    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    // Health check
    if (path === '/health') {
      return this.base.createJsonResponse({ status: 'healthy', service: 'user-service' });
    }

    // GET /users - list users
    if (path === '/users' && method === 'GET') {
      return this.listUsers(url);
    }

    // GET /users/:id - get user by id
    const userMatch = path.match(/^\/users\/([a-zA-Z0-9-]+)$/);
    if (userMatch && method === 'GET') {
      return this.getUser(userMatch[1]);
    }

    // POST /users - create user
    if (path === '/users' && method === 'POST') {
      return this.createUser(request);
    }

    // PUT /users/:id - update user
    if (userMatch && method === 'PUT') {
      return this.updateUser(userMatch[1], request);
    }

    // DELETE /users/:id - delete user
    if (userMatch && method === 'DELETE') {
      return this.deleteUser(userMatch[1]);
    }

    // GET /users/:id/profile - get user profile (demonstrates internal service-to-service call)
    const profileMatch = path.match(/^\/users\/([a-zA-Z0-9-]+)\/profile$/);
    if (profileMatch && method === 'GET') {
      return this.getUserProfile(profileMatch[1]);
    }

    return this.base.createErrorResponse('Route not found in user-service', 404);
  }

  async listUsers(url) {
    const page = parseInt(url.searchParams.get('page') || '1');
    const limit = parseInt(url.searchParams.get('limit') || '10');

    // In production, this would query a database (D1, KV, etc.)
    const users = await this.fetchUsersFromStore(page, limit);

    return this.base.createJsonResponse({
      data: users,
      pagination: { page, limit, total: users.length },
      service: 'user-service'
    });
  }

  async getUser(userId) {
    const user = await this.fetchUserFromStore(userId);

    if (!user) {
      return this.base.createErrorResponse(`User ${userId} not found`, 404);
    }

    return this.base.createJsonResponse({ data: user, service: 'user-service' });
  }

  async createUser(request) {
    try {
      const body = await request.json();

      if (!body.email || !body.name) {
        return this.base.createErrorResponse('Missing required fields: email, name', 400);
      }

      const newUser = {
        id: crypto.randomUUID(),
        name: body.name,
        email: body.email,
        createdAt: new Date().toISOString()
      };

      // Store user (using KV in this example)
      if (this.env.USER_KV) {
        await this.env.USER_KV.put(`user:${newUser.id}`, JSON.stringify(newUser));
        // Maintain an index
        const index = JSON.parse(await this.env.USER_KV.get('user:index') || '[]');
        index.push(newUser.id);
        await this.env.USER_KV.put('user:index', JSON.stringify(index));
      }

      return this.base.createJsonResponse({ data: newUser, service: 'user-service' }, 201);
    } catch (err) {
      return this.base.createErrorResponse(`Invalid request body: ${err.message}`, 400);
    }
  }

  async updateUser(userId, request) {
    try {
      const body = await request.json();
      const existingUser = await this.fetchUserFromStore(userId);

      if (!existingUser) {
        return this.base.createErrorResponse(`User ${userId} not found`, 404);
      }

      const updatedUser = {
        ...existingUser,
        ...body,
        id: userId, // prevent id override
        updatedAt: new Date().toISOString()
      };

      if (this.env.USER_KV) {
        await this.env.USER_KV.put(`user:${userId}`, JSON.stringify(updatedUser));
      }

      return this.base.createJsonResponse({ data: updatedUser, service: 'user-service' });
    } catch (err) {
      return this.base.createErrorResponse(`Invalid request body: ${err.message}`, 400);
    }
  }

  async deleteUser(userId) {
    const existingUser = await this.fetchUserFromStore(userId);

    if (!existingUser) {
      return this.base.createErrorResponse(`User ${userId} not found`, 404);
    }

    if (this.env.USER_KV) {
      await this.env.USER_KV.delete(`user:${userId}`);
      const index = JSON.parse(await this.env.USER_KV.get('user:index') || '[]');
      const newIndex = index.filter(id => id !== userId);
      await this.env.USER_KV.put('user:index', JSON.stringify(newIndex));
    }

    return this.base.createJsonResponse({ message: `User ${userId} deleted`, service: 'user-service' });
  }

  async getUserProfile(userId) {
    const user = await this.fetchUserFromStore(userId);

    if (!user) {
      return this.base.createErrorResponse(`User ${userId} not found`, 404);
    }

    // Demonstrate calling another internal service via service binding
    let orderHistory = [];
    if (this.env.ORDER_SERVICE) {
      try {
        const orderResponse = await this.env.ORDER_SERVICE.fetch(
          new Request(`https://internal/orders?userId=${userId}`, {
            headers: {
              'X-Internal-Caller': 'user-service',
              'X-Request-Id': crypto.randomUUID()
            }
          })
        );
        if (orderResponse.ok) {
          const orderData = await orderResponse.json();
          orderHistory = orderData.data || [];
        }
      } catch (err) {
        console.error(`Failed to fetch orders for user ${userId}: ${err.message}`);
      }
    }

    return this.base.createJsonResponse({
      data: {
        ...user,
        orderHistory,
        profileComplete: !!(user.name && user.email)
      },
      service: 'user-service'
    });
  }

  async fetchUsersFromStore(page, limit) {
    if (this.env.USER_KV) {
      const index = JSON.parse(await this.env.USER_KV.get('user:index') || '[]');
      const start = (page - 1) * limit;
      const pageIds = index.slice(start, start + limit);
      const users = await Promise.all(
        pageIds.map(async (id) => {
          const data = await this.env.USER_KV.get(`user:${id}`);
          return data ? JSON.parse(data) : null;
        })
      );
      return users.filter(Boolean);
    }

    // Fallback mock data
    return [
      { id: 'user-1', name: 'Alice Johnson', email: 'alice@example.com', createdAt: '2024-01-15T10:00:00Z' },
      { id: 'user-2', name: 'Bob Smith', email: 'bob@example.com', createdAt: '2024-01-16T11:00:00Z' },
    ];
  }

  async fetchUserFromStore(userId) {
    if (this.env.USER_KV) {
      const data = await this.env.USER_KV.get(`user:${userId}`);
      return data ? JSON.parse(data) : null;
    }

    // Fallback mock
    const mockUsers = {
      'user-1': { id: 'user-1', name: 'Alice Johnson', email: 'alice@example.com', createdAt: '2024-01-15T10:00:00Z' },
      'user-2': { id: 'user-2', name: 'Bob Smith', email: 'bob@example.com', createdAt: '2024-01-16T11:00:00Z' },
    };
    return mockUsers[userId] || null;
  }
}

